svg.script:
const DATA_KEY = "woodland_outer_sheet_svg_text_v2";
const LAYOUT_KEY = "woodland_outer_sheet_svg_layout_v2";
const fields = [...document.querySelectorAll(".field")];
let active = null;
let data = {};
let layout = {};
let drag = null;

try { data = JSON.parse(localStorage.getItem(DATA_KEY) || "{}"); } catch (e) { data = {}; }
try { layout = JSON.parse(localStorage.getItem(LAYOUT_KEY) || "{}"); } catch (e) { layout = {}; }

function setPos(g, x, y) {
  g.setAttribute("transform", `translate(${x},${y})`);
  g.dataset.x = x;
  g.dataset.y = y;
}

function renderField(g) {
  const id = g.dataset.id;
  const text = g.querySelector(".value");
  const val = data[id] || "";
  text.textContent = val;
  g.classList.toggle("filled", val.length > 0);
}

function saveText() { localStorage.setItem(DATA_KEY, JSON.stringify(data)); }
function saveLayout() { localStorage.setItem(LAYOUT_KEY, JSON.stringify(layout)); }

function activate(g) {
  if (active) active.classList.remove("active");
  active = g;
  active.classList.add("active");
  active.focus();
}

function svgPoint(evt) {
  const svg = document.documentElement;
  const pt = svg.createSVGPoint();
  pt.x = evt.clientX; pt.y = evt.clientY;
  return pt.matrixTransform(svg.getScreenCTM().inverse());
}

fields.forEach(g => {
  const id = g.dataset.id;
  const p = layout[id] || {x: Number(g.dataset.defaultX), y: Number(g.dataset.defaultY)};
  setPos(g, p.x, p.y);
  renderField(g);

  g.addEventListener("click", () => activate(g));
  g.addEventListener("focus", () => activate(g));

  g.addEventListener("pointerdown", e => {
    activate(g);
    if (!e.shiftKey) return;
    const p = svgPoint(e);
    drag = {
      g,
      id,
      startX: p.x,
      startY: p.y,
      origX: Number(g.dataset.x),
      origY: Number(g.dataset.y)
    };
    g.classList.add("dragging");
    g.setPointerCapture(e.pointerId);
    e.preventDefault();
  });

  g.addEventListener("pointermove", e => {
    if (!drag || drag.g !== g) return;
    const p = svgPoint(e);
    const nx = Math.round(drag.origX + (p.x - drag.startX));
    const ny = Math.round(drag.origY + (p.y - drag.startY));
    setPos(g, nx, ny);
    layout[id] = {x:nx, y:ny};
    e.preventDefault();
  });

  g.addEventListener("pointerup", e => {
    if (!drag || drag.g !== g) return;
    g.classList.remove("dragging");
    saveLayout();
    drag = null;
    e.preventDefault();
  });
});

document.addEventListener("keydown", e => {
  if (!active) return;
  const id = active.dataset.id;

  if (e.key === "Escape") {
    active.classList.remove("active");
    active = null;
    return;
  }

  if (e.key === "Backspace") {
    data[id] = (data[id] || "").slice(0, -1);
    renderField(active);
    saveText();
    e.preventDefault();
    return;
  }

  if (e.key === "Delete") {
    data[id] = "";
    renderField(active);
    saveText();
    e.preventDefault();
    return;
  }

  if (e.key === "Tab" || e.key === "Enter") {
    const i = fields.indexOf(active);
    activate(fields[(i + 1) % fields.length]);
    e.preventDefault();
    return;
  }

  if (e.key.length === 1 && !e.metaKey && !e.ctrlKey && !e.altKey) {
    data[id] = (data[id] || "") + e.key;
    renderField(active);
    saveText();
    e.preventDefault();
  }
});
